const ls = { get: (k, d) => { try { const v = localStorage.getItem(k); return v ? JSON.parse(v) : d; } catch { return d; } }, set: (k, v) => { try { localStorage.setItem(k, JSON.stringify(v)); } catch {} } };
const openTg = (path, msg = "") => window.open(`https://t.me/${path}${msg ? "?text=" + encodeURIComponent(msg) : ""}`, "_blank");
function getGreeting(lang) { const h = new Date().getHours(); const g = h < 6 ? "🌙" : h < 12 ? "🌅" : h < 18 ? "☀️" : "🌆"; const map = { ru: [g+" Доброй ночи",g+" Доброе утро",g+" Добрый день",g+" Добрый вечер"], en: [g+" Good night",g+" Good morning",g+" Good afternoon",g+" Good evening"] }; return (map[lang]||map.ru)[h<6?0:h<12?1:h<18?2:3]; }
function getStreak() { const data = ls.get("rs_streak",{last:"",count:0,xp:0}); const today = new Date().toDateString(); const yesterday = new Date(Date.now()-86400000).toDateString(); if(data.last===today) return data; if(data.last===yesterday){data.count++;data.last=today;data.xp+=10;} else {data.count=1;data.last=today;data.xp+=5;} ls.set("rs_streak",data); return data; }
function addXP(amount) { const data = ls.get("rs_streak",{last:"",count:0,xp:0}); data.xp+=amount; ls.set("rs_streak",data); return data; }
function getLevel(xp) { return Math.floor(xp/100)+1; }
function getLevelProgress(xp) { return (xp%100)/100; }
// ── PARTICLES ──
function ParticlesBg({ accent }) { const canRef = useRef(null); useEffect(() => { const canvas = canRef.current; if(!canvas) return; const ctx = canvas.getContext("2d"); if(!ctx) return; let raf; const resize = () => { canvas.width=window.innerWidth; canvas.height=window.innerHeight; }; resize(); window.addEventListener("resize",resize); const particles = Array.from({length:35},()=>({x:Math.random()*canvas.width,y:Math.random()*canvas.height,vx:(Math.random()-0.5)*0.3,vy:(Math.random()-0.5)*0.3,r:Math.random()*2+0.5,a:Math.random()*0.3+0.05})); const draw = () => { ctx.clearRect(0,0,canvas.width,canvas.height); particles.forEach(p=>{p.x+=p.vx;p.y+=p.vy;if(p.x<0)p.x=canvas.width;if(p.x>canvas.width)p.x=0;if(p.y<0)p.y=canvas.height;if(p.y>canvas.height)p.y=0;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=accent;ctx.globalAlpha=p.a;ctx.fill();}); ctx.globalAlpha=0.04;ctx.strokeStyle=accent;ctx.lineWidth=0.5; for(let i=0;i<particles.length;i++){for(let j=i+1;j<particles.length;j++){const dx=particles[i].x-particles[j].x,dy=particles[i].y-particles[j].y;if(Math.sqrt(dx*dx+dy*dy)<120){ctx.beginPath();ctx.moveTo(particles[i].x,particles[i].y);ctx.lineTo(particles[j].x,particles[j].y);ctx.stroke();}}} ctx.globalAlpha=1; raf=requestAnimationFrame(draw); }; draw(); return ()=>{cancelAnimationFrame(raf);window.removeEventListener("resize",resize);}; },[accent]); return <canvas ref={canRef} style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:0}} />; }
// ── CONFETTI ──
function Confetti({ active, accent }) { const canRef = useRef(null); useEffect(() => { if(!active) return; const canvas = canRef.current; if(!canvas) return; const ctx = canvas.getContext("2d"); if(!ctx) return; canvas.width=window.innerWidth; canvas.height=window.innerHeight; const pieces = Array.from({length:60},()=>({x:Math.random()*canvas.width,y:-10,vx:(Math.random()-0.5)*4,vy:Math.random()*4+2,rot:Math.random()*360,rotV:(Math.random()-0.5)*8,w:Math.random()*10+4,h:Math.random()*6+3,color:[accent,"#fff","#fbbf24","#f472b6","#34d399"][Math.floor(Math.random()*5)],life:1})); let raf; const draw = () => { ctx.clearRect(0,0,canvas.width,canvas.height); let alive=false; pieces.forEach(p=>{p.x+=p.vx;p.y+=p.vy;p.rot+=p.rotV;p.life-=0.008;if(p.life>0&&p.y<canvas.height){alive=true;ctx.save();ctx.translate(p.x,p.y);ctx.rotate(p.rot*Math.PI/180);ctx.globalAlpha=p.life;ctx.fillStyle=p.color;ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h);ctx.restore();}}); if(alive) raf=requestAnimationFrame(draw); }; draw(); return ()=>cancelAnimationFrame(raf); },[active,accent]); return <canvas ref={canRef} style={{position:"fixed",inset:0,width:"100%",height:"100%",pointerEvents:"none",zIndex:9999}} />; }
