function GalleryTab({th,t,lang,wishlist,toggleWishlist,onOpenImage}) { const items=GALLERY[lang]||GALLERY.ru; const cats=useMemo(()=>["all",...[...new Set(items.map(i=>i.cat))]],[items]); const [cat,setCat]=useState("all"); const [search,setSearch]=useState(""); const [view,setView]=useState("grid"); const [sort,setSort]=useState("pop"); const filtered=useMemo(()=>{let r=items.filter(i=>(cat==="all"||i.cat===cat)&&(search===""||i.title.toLowerCase().includes(search.toLowerCase())||i.tags.some(t=>t.includes(search.toLowerCase()))));if(sort==="pop") r=[...r].sort((a,b)=>(b.popular?1:0)-(a.popular?1:0));if(sort==="new") r=[...r].reverse();if(sort==="alpha") r=[...r].sort((a,b)=>a.title.localeCompare(b.title));return r;},[items,cat,search,sort]); return (<div style={{display:"flex",flexDirection:"column",gap:12}}><div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}><div><div style={{fontSize:22,fontWeight:900,color:th.text}}>{t.galleryTitle}</div><div style={{fontSize:12,color:th.sub}}>{filtered.length} works</div></div><button onClick={()=>{SFX.filter();setView(v=>v==="grid"?"list":"grid");}} style={{width:36,height:36,borderRadius:10,border:`1px solid ${th.border}`,background:th.card,color:th.sub,cursor:"pointer",fontSize:14,display:"flex",alignItems:"center",justifyContent:"center"}}>{view==="grid"?"≡":"⊞"}</button></div><div style={{position:"relative"}}><span style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",fontSize:14,color:th.sub}}>◎</span><input value={search} onChange={e=>setSearch(e.target.value)} placeholder={t.gallerySearch} style={{width:"100%",padding:"10px 12px 10px 36px",borderRadius:14,border:`1px solid ${th.border}`,background:th.card,color:th.text,fontSize:13,outline:"none",fontFamily:"inherit",boxSizing:"border-box"}}/>{search&&<button onClick={()=>setSearch("")} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",color:th.sub,cursor:"pointer",fontSize:16}}>✕</button>}</div><div style={{display:"flex",gap:6}}>{[["pop",t.sortPop],["new",t.sortNew],["alpha",t.sortAlpha]].map(([v,l])=>(<button key={v} onClick={()=>{SFX.filter();setSort(v);}} style={{flex:1,padding:"7px 6px",borderRadius:10,border:`1px solid ${sort===v?th.accent:th.border}`,background:sort===v?th.accent+"22":"transparent",color:sort===v?th.accent:th.sub,fontSize:11,fontWeight:700,cursor:"pointer"}}>{l}</button>))}</div><div style={{display:"flex",gap:6,overflowX:"auto",scrollbarWidth:"none",WebkitOverflowScrolling:"touch"}}>{cats.map(c=>{const active=cat===c;const icon=c==="all"?"◆":(CAT_ICONS[c]||"◈");return(<button key={c} onClick={()=>{setCat(c);SFX.filter();}} style={{whiteSpace:"nowrap",display:"flex",alignItems:"center",gap:5,padding:"7px 14px",borderRadius:999,fontSize:12,fontWeight:700,cursor:"pointer",background:active?th.grad:"transparent",color:active?th.btnTxt:th.sub,border:`1px solid ${active?"transparent":th.border}`,flexShrink:0}}><span>{icon}</span> {c==="all"?t.filterAll:c}</button>);})}</div>{filtered.length===0?(<div style={{textAlign:"center",padding:"40px 20px",color:th.sub}}><div style={{fontSize:40,marginBottom:12}}>◎</div><div>Nothing found</div></div>):view==="grid"?(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>{filtered.map((item,i)=>{const wl=wishlist.includes(item.id);return(<div key={item.id} style={{borderRadius:18,overflow:"hidden",background:th.card,border:`1px solid ${th.border}`,cursor:"pointer",animation:`cardIn .35s ease ${i*.04}s both`}}><div onClick={()=>{onOpenImage(item);SFX.open();}} style={{position:"relative"}}><img src={item.img} alt={item.title} loading="lazy" style={{width:"100%",height:110,objectFit:"cover",display:"block"}}/>{item.popular&&<div style={{position:"absolute",top:6,left:6,padding:"2px 7px",borderRadius:999,background:th.accent,color:th.btnTxt,fontSize:9,fontWeight:800}}>★ TOP</div>}</div><div style={{padding:"9px 10px 10px"}}><div style={{fontSize:12,fontWeight:700,color:th.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.title}</div><div style={{fontSize:10,color:th.sub,marginBottom:8}}>{item.desc}</div><div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}><div style={{fontSize:9,color:th.accent,fontWeight:600}}>{t.zoomHint}</div><button onClick={e=>{e.stopPropagation();toggleWishlist(item.id);SFX.wishlist();}} style={{width:24,height:24,borderRadius:8,border:`1px solid ${wl?th.accent:th.border}`,background:wl?th.accent+"22":"transparent",color:wl?th.accent:th.sub,cursor:"pointer",fontSize:12,display:"flex",alignItems:"center",justifyContent:"center"}}>{wl?"♥":"♡"}</button></div></div></div>);})}</div>):(<div style={{display:"flex",flexDirection:"column",gap:8}}>{filtered.map((item,i)=>(<div key={item.id} onClick={()=>{onOpenImage(item);SFX.open();}} style={{display:"flex",gap:12,alignItems:"center",background:th.card,borderRadius:16,border:`1px solid ${th.border}`,padding:"10px 12px",cursor:"pointer",animation:`cardIn .3s ease ${i*.04}s both`}}><img src={item.img} alt={item.title} loading="lazy" style={{width:64,height:48,objectFit:"cover",borderRadius:10,flexShrink:0}}/><div style={{flex:1,minWidth:0}}><div style={{fontSize:13,fontWeight:700,color:th.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.title}</div><div style={{fontSize:11,color:th.sub}}>{item.cat}</div></div><button onClick={e=>{e.stopPropagation();toggleWishlist(item.id);SFX.wishlist();}} style={{width:30,height:30,borderRadius:9,border:`1px solid ${wishlist.includes(item.id)?th.accent:th.border}`,background:wishlist.includes(item.id)?th.accent+"22":"transparent",color:wishlist.includes(item.id)?th.accent:th.sub,cursor:"pointer",fontSize:14,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center"}}>{wishlist.includes(item.id)?"♥":"♡"}</button></div>))}</div>)}</div>); }
