function CoursesTab({th,t,lang,showToast,addXPfn}) { const courses=COURSES_DATA[lang]||COURSES_DATA.ru; const cats=useMemo(()=>["all",...[...new Set(courses.map(c=>c.cat))]],[courses]); const [cat,setCat]=useState("all"); const [selCourse,setSelCourse]=useState(null); const [progress,setProgress]=useState(()=>ls.get("rs_course_prog",{})); const [quizMode,setQuizMode]=useState(false); const [quizIdx,setQuizIdx]=useState(0); const [quizScore,setQuizScore]=useState(0); const [quizAnswer,setQuizAnswer]=useState(null); const [quizDone,setQuizDone]=useState(false); const L=LANGS[lang]||LANGS.ru; const fmt=usd=>usd===0?t.courseFree:`${Math.round(usd*L.rate)} ${L.cur}`; const filtered=useMemo(()=>courses.filter(c=>cat==="all"||c.cat===c),[courses,cat]); const completeTopic=(courseId,topicIdx)=>{const newProg={...progress};if(!newProg[courseId])newProg[courseId]=[];if(!newProg[courseId].includes(topicIdx)){newProg[courseId]=[...newProg[courseId],topicIdx];addXPfn(15);SFX.success();showToast("+15 XP! ⚡","success");}setProgress(newProg);ls.set("rs_course_prog",newProg);}; const getCourseProgress=(courseId,total)=>{const done=progress[courseId]?.length||0;return Math.round((done/total)*100);}; const quizQ=QUIZ_DATA[quizIdx]; const handleQuizAnswer=idx=>{if(quizAnswer!==null)return;setQuizAnswer(idx);if(idx===quizQ.correct){setQuizScore(s=>s+1);SFX.quizCorrect();addXPfn(20);}else{SFX.quizWrong();}setTimeout(()=>{if(quizIdx<QUIZ_DATA.length-1){setQuizIdx(i=>i+1);setQuizAnswer(null);}else{setQuizDone(true);SFX.levelUp();addXPfn(50);showToast(`🏆 ${t.quizResult}: ${quizScore+(idx===quizQ.correct?1:0)}/${QUIZ_DATA.length}`,"success");}},1200);}; if(quizMode){return(<div style={{display:"flex",flexDirection:"column",gap:14,animation:"cardIn .35s ease both"}}><div style={{display:"flex",alignItems:"center",gap:10}}><button onClick={()=>{setQuizMode(false);setQuizIdx(0);setQuizScore(0);setQuizAnswer(null);setQuizDone(false);SFX.close();}} style={{width:36,height:36,borderRadius:10,border:`1px solid ${th.border}`,background:th.card,color:th.sub,cursor:"pointer",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}}>←</button><div style={{fontSize:18,fontWeight:900,color:th.text}}>{t.quizTitle}</div><div style={{marginLeft:"auto",fontSize:13,fontWeight:700,color:th.accent}}>{t.quizScore}: {quizScore}/{QUIZ_DATA.length}</div></div><div style={{height:4,borderRadius:999,background:th.border,overflow:"hidden"}}><div style={{height:"100%",width:`${((quizIdx+(quizDone?1:0))/QUIZ_DATA.length)*100}%`,borderRadius:999,background:th.grad,transition:"width .3s ease"}}/></div>{quizDone?(<div style={{textAlign:"center",padding:"40px 20px",animation:"cardIn .35s ease both"}}><div style={{fontSize:60,marginBottom:16}}>🏆</div><div style={{fontSize:24,fontWeight:900,color:th.text,marginBottom:8}}>{t.quizResult}!</div><div style={{fontSize:40,fontWeight:900,color:th.accent,marginBottom:16}}>{quizScore}/{QUIZ_DATA.length}</div><button onClick={()=>{setQuizMode(false);setQuizIdx(0);setQuizScore(0);setQuizAnswer(null);setQuizDone(false);}} style={{background:th.grad,color:th.btnTxt,border:"none",borderRadius:14,padding:"14px 28px",fontSize:14,fontWeight:800,cursor:"pointer",boxShadow:th.shadow}}>OK</button></div>):(<div style={{background:th.card,borderRadius:22,border:`1px solid ${th.border}`,padding:"22px",animation:"cardIn .3s ease both"}}><div style={{fontSize:12,color:th.sub,fontWeight:700,marginBottom:12}}>{quizIdx+1}/{QUIZ_DATA.length}</div><div style={{fontSize:16,fontWeight:800,color:th.text,marginBottom:20,lineHeight:1.5}}>{quizQ.q}</div><div style={{display:"flex",flexDirection:"column",gap:10}}>{quizQ.opts.map((opt,i)=>{let bg="transparent",brd=th.border,clr=th.text;if(quizAnswer!==null){if(i===quizQ.correct){bg="#10b98122";brd="#10b981";clr="#10b981";}else if(i===quizAnswer){bg="#ef444422";brd="#ef4444";clr="#ef4444";}}return(<button key={i} onClick={()=>handleQuizAnswer(i)} style={{padding:"14px 16px",borderRadius:14,border:`1px solid ${brd}`,background:bg,color:clr,cursor:quizAnswer!==null?"default":"pointer",fontSize:14,fontWeight:600,textAlign:"left",transition:"all .2s"}}>{opt}</button>);})}</div>{quizAnswer!==null&&(<div style={{marginTop:14,textAlign:"center",fontSize:14,fontWeight:800,color:quizAnswer===quizQ.correct?"#10b981":"#ef4444",animation:"fadeIn .2s ease"}}>{quizAnswer===quizQ.correct?t.quizCorrect:t.quizWrong}</div>)}</div>)}</div>);} if(selCourse){const prog=getCourseProgress(selCourse.id,selCourse.topics.length);return(<div style={{display:"flex",flexDirection:"column",gap:12,animation:"cardIn .35s ease both"}}><button onClick={()=>{setSelCourse(null);SFX.close();}} style={{alignSelf:"flex-start",display:"flex",alignItems:"center",gap:6,padding:"8px 14px",borderRadius:10,border:`1px solid ${th.border}`,background:th.card,color:th.sub,cursor:"pointer",fontSize:13,fontWeight:700}}>← {t.coursesTitle}</button><img src={selCourse.img} alt={selCourse.title} style={{width:"100%",borderRadius:20,height:180,objectFit:"cover"}}/><div><div style={{display:"flex",gap:8,marginBottom:8}}><span style={{padding:"3px 10px",borderRadius:999,background:th.accent+"22",color:th.accent,fontSize:11,fontWeight:700}}>{selCourse.level}</span><span style={{padding:"3px 10px",borderRadius:999,background:th.surface,color:th.sub,fontSize:11,fontWeight:700}}>{selCourse.duration}</span><span style={{padding:"3px 10px",borderRadius:999,background:selCourse.free?"#10b98122":"#fbbf2422",color:selCourse.free?"#10b981":"#fbbf24",fontSize:11,fontWeight:700}}>{fmt(selCourse.price)}</span></div><div style={{fontSize:22,fontWeight:900,color:th.text,marginBottom:4}}>{selCourse.title}</div><div style={{fontSize:13,color:th.sub}}>{selCourse.desc}</div></div><div style={{background:th.card,borderRadius:14,border:`1px solid ${th.border}`,padding:"12px 16px"}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}><span style={{fontSize:12,fontWeight:700,color:th.text}}>{t.courseProgress}</span><span style={{fontSize:12,fontWeight:700,color:th.accent}}>{prog}%</span></div><div style={{height:6,borderRadius:999,background:th.border,overflow:"hidden"}}><div style={{height:"100%",width:`${prog}%`,borderRadius:999,background:th.grad,transition:"width .5s ease"}}/></div></div><div style={{fontSize:14,fontWeight:800,color:th.text}}>{t.courseTopics}</div><div style={{display:"flex",flexDirection:"column",gap:6}}>{selCourse.topics.map((topic,i)=>{const done=progress[selCourse.id]?.includes(i);return(<div key={i} onClick={()=>completeTopic(selCourse.id,i)} style={{display:"flex",alignItems:"center",gap:12,padding:"12px 14px",borderRadius:14,border:`1px solid ${done?th.accent+"40":th.border}`,background:done?th.accent+"12":th.card,cursor:"pointer",animation:`cardIn .3s ease ${i*.03}s both`}}><div style={{width:28,height:28,borderRadius:8,background:done?th.accent:th.surface,display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,color:done?th.btnTxt:th.sub,fontWeight:800,flexShrink:0}}>{done?"✓":i+1}</div><span style={{fontSize:13,fontWeight:600,color:done?th.accent:th.text}}>{topic}</span>{done&&<span style={{marginLeft:"auto",fontSize:10,color:th.accent,fontWeight:700}}>+15 XP</span>}</div>);})}</div>{!selCourse.free&&(<button onClick={()=>{SFX.order();openTg("Rivaldsg",`Хочу курс: ${selCourse.title}`);}} style={{background:th.grad,color:th.btnTxt,border:"none",borderRadius:16,padding:"15px",fontSize:15,fontWeight:800,cursor:"pointer",boxShadow:th.shadow}}>✈ {t.orderBtn} — {fmt(selCourse.price)}</button>)}</div>);} return (<div style={{display:"flex",flexDirection:"column",gap:12}}><div><div style={{fontSize:22,fontWeight:900,color:th.text}}>{t.coursesTitle}</div><div style={{fontSize:12,color:th.sub}}>{t.courseSub}</div></div><div onClick={()=>{setQuizMode(true);SFX.quiz();addXPfn(5);}} style={{background:th.grad,borderRadius:20,padding:"18px 20px",cursor:"pointer",boxShadow:th.shadow,display:"flex",alignItems:"center",gap:14,animation:"cardIn .35s ease both"}}><div style={{fontSize:36}}>🧠</div><div><div style={{fontSize:15,fontWeight:900,color:th.btnTxt}}>{t.quizTitle}</div><div style={{fontSize:12,color:th.btnTxt+"cc"}}>{QUIZ_DATA.length} вопросов · +XP</div></div><span style={{marginLeft:"auto",fontSize:20,color:th.btnTxt}}>→</span></div><div style={{display:"flex",gap:6,overflowX:"auto",scrollbarWidth:"none",WebkitOverflowScrolling:"touch"}}>{cats.map(c=>(<button key={c} onClick={()=>{setCat(c);SFX.filter();}} style={{whiteSpace:"nowrap",padding:"7px 14px",borderRadius:999,fontSize:12,fontWeight:700,cursor:"pointer",background:cat===c?th.grad:"transparent",color:cat===c?th.btnTxt:th.sub,border:`1px solid ${cat===c?"transparent":th.border}`,flexShrink:0}}>{c==="all"?t.filterAll:c}</button>))}</div><div style={{display:"flex",flexDirection:"column",gap:12}}>{filtered.map((course,i)=>{const prog=getCourseProgress(course.id,course.topics.length);return(<div key={course.id} onClick={()=>{setSelCourse(course);SFX.course();addXPfn(3);}} style={{background:th.card,borderRadius:22,border:`1px solid ${th.border}`,overflow:"hidden",cursor:"pointer",animation:`cardIn .35s ease ${i*.05}s both`}}><div style={{position:"relative"}}><img src={course.img} alt={course.title} loading="lazy" style={{width:"100%",height:140,objectFit:"cover",display:"block"}}/><div style={{position:"absolute",top:8,left:8,display:"flex",gap:6}}>{course.popular&&<span style={{padding:"3px 8px",borderRadius:999,background:th.accent,color:th.btnTxt,fontSize:9,fontWeight:800}}>★ TOP</span>}<span style={{padding:"3px 8px",borderRadius:999,background:course.free?"#10b981":"#fbbf24",color:course.free?"#fff":"#000",fontSize:9,fontWeight:800}}>{fmt(course.price)}</span></div></div><div style={{padding:"14px 16px"}}><div style={{fontSize:15,fontWeight:800,color:th.text,marginBottom:4}}>{course.title}</div><div style={{fontSize:12,color:th.sub,marginBottom:10}}>{course.desc}</div><div style={{display:"flex",gap:8,marginBottom:10,flexWrap:"wrap"}}><span style={{fontSize:10,color:th.accent,fontWeight:700,padding:"2px 8px",borderRadius:999,background:th.accent+"18"}}>{course.level}</span><span style={{fontSize:10,color:th.sub,fontWeight:600}}>⏱ {course.duration}</span><span style={{fontSize:10,color:th.sub,fontWeight:600}}>📚 {course.lessons} {t.courseLessons}</span></div>{prog>0&&(<div><div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}><span style={{fontSize:10,color:th.sub,fontWeight:600}}>{t.courseProgress}</span><span style={{fontSize:10,color:th.accent,fontWeight:700}}>{prog}%</span></div><div style={{height:4,borderRadius:999,background:th.border,overflow:"hidden"}}><div style={{height:"100%",width:`${prog}%`,borderRadius:999,background:th.grad}}/></div></div>)}</div></div>);})}</div></div>); }
