function PricingTab({th,t,lang,cart,addToCart,removeFromCart,updateQty,clearCart,showToast}) { const L=LANGS[lang]||LANGS.ru; const fmt=usd=>`${Math.round(usd*L.rate)} ${L.cur}`; const [promo,setPromo]=useState(""); const [promoDisc,setPromoDisc]=useState(0); const [calcComplexity,setCalcComplexity]=useState(1); const [calcUrgent,setCalcUrgent]=useState(1); const [calcItems,setCalcItems]=useState(["avatar"]); const applyPromo=()=>{const code=PROMO_CODES[promo.toUpperCase()];if(code){setPromoDisc(code.discount);SFX.promo();showToast(`${t.promoSuccess} -${code.discount}%`,"success");}else{SFX.error();showToast(t.promoError,"error");}}; const cartTotal=useMemo(()=>{const items=cart.reduce((s,i)=>s+i.qty,0);const sub=cart.reduce((s,i)=>s+i.priceUSD*i.qty,0);let disc=items>=2?sub*.1:0;if(promoDisc>0)disc+=sub*(promoDisc/100);return{items,sub,disc:Math.min(disc,sub),total:Math.max(sub-disc,0)};},[cart,promoDisc]); const getSvcName=svc=>svc[lang]||svc.en; const getSvcDesc=svc=>lang==="en"?svc.descEn:svc.descRu; const calcBase=calcItems.length*5; const calcTotal2=Math.round(calcBase*calcComplexity*calcUrgent); return (<div style={{display:"flex",flexDirection:"column",gap:12}}><div><div style={{fontSize:22,fontWeight:900,color:th.text}}>{t.pricingTitle}</div><div style={{fontSize:12,color:th.sub,marginTop:2}}>{t.pricingHint.replace("{cur}",L.cur).replace("{rate}",L.rate).replace("{cur}",L.cur)}</div></div><div style={{padding:"10px 14px",borderRadius:12,background:th.accent+"18",border:`1px solid ${th.accent}40`,fontSize:12,color:th.accent,fontWeight:600}}>{t.discountNote}</div>{SERVICES.map((svc,i)=>{const inCart=cart.find(c=>c.id===svc.id);return(<div key={svc.id} style={{background:th.card,borderRadius:20,border:`1px solid ${inCart?th.accent:th.border}`,padding:"16px",boxShadow:inCart?th.shadow:"none",animation:`cardIn .4s ease ${i*.08}s both`}}><div style={{display:"flex",alignItems:"center",gap:14}}><div style={{width:48,height:48,borderRadius:15,background:th.grad,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0,boxShadow:th.shadow}}>{svc.icon}</div><div style={{flex:1}}><div style={{fontSize:15,fontWeight:800,color:th.text}}>{getSvcName(svc)}</div><div style={{fontSize:11,color:th.sub,marginTop:2}}>{getSvcDesc(svc)}</div></div><div style={{fontSize:20,fontWeight:900,color:th.accent,flexShrink:0}}>{fmt(svc.priceUSD)}</div></div><div style={{marginTop:14,display:"flex",gap:8,alignItems:"center"}}>{!inCart?(<button onClick={()=>{addToCart(svc,getSvcName(svc));showToast(getSvcName(svc)+" → 🛒","success");SFX.addCart();}} style={{flex:1,background:th.grad,color:th.btnTxt,border:"none",borderRadius:12,padding:"11px",fontSize:13,fontWeight:800,cursor:"pointer",boxShadow:th.shadow}}>{t.addCart}</button>):(<><button onClick={()=>{updateQty(svc.id,inCart.qty-1);SFX.tap();}} style={{width:38,height:38,borderRadius:11,border:`1px solid ${th.border}`,background:"transparent",color:th.text,cursor:"pointer",fontSize:18,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center"}}>−</button><div style={{flex:1,textAlign:"center"}}><div style={{fontSize:18,fontWeight:900,color:th.accent}}>{inCart.qty}</div><div style={{fontSize:10,color:th.sub}}>{t.quantityLabel}</div></div><button onClick={()=>{updateQty(svc.id,inCart.qty+1);SFX.tap();}} style={{width:38,height:38,borderRadius:11,border:"none",background:th.accent,color:th.btnTxt,cursor:"pointer",fontSize:18,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center"}}>+</button><button onClick={()=>{removeFromCart(svc.id);SFX.remove();}} style={{width:38,height:38,borderRadius:11,border:"1px solid #ef444440",background:"#ef444418",color:"#ef4444",cursor:"pointer",fontSize:14,display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button></>)}</div></div>)})}<div style={{background:th.card,borderRadius:18,border:`1px solid ${th.border}`,padding:"14px 16px"}}><div style={{fontSize:13,fontWeight:800,color:th.text,marginBottom:10}}>🎁 Промокод</div><div style={{display:"flex",gap:8}}><input value={promo} onChange={e=>setPromo(e.target.value)} placeholder={t.promoPlaceholder} style={{flex:1,padding:"10px 14px",borderRadius:12,border:`1px solid ${th.border}`,background:th.surface,color:th.text,fontSize:13,outline:"none",fontFamily:"inherit",textTransform:"uppercase"}}/><button onClick={applyPromo} style={{padding:"10px 16px",borderRadius:12,background:th.grad,color:th.btnTxt,border:"none",fontSize:12,fontWeight:800,cursor:"pointer",flexShrink:0}}>{t.promoApply}</button></div>{promoDisc>0&&<div style={{marginTop:8,fontSize:12,color:"#10b981",fontWeight:700}}>✓ −{promoDisc}%</div>}</div><div style={{background:th.card,borderRadius:22,border:`1px solid ${th.border}`,padding:"18px"}}><div style={{fontSize:15,fontWeight:900,color:th.text,marginBottom:14}}>🧮 {t.calcTitle}</div><div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14}}>{SERVICES.map(s=>{const sel=calcItems.includes(s.key);return(<button key={s.key} onClick={()=>{SFX.tap();setCalcItems(prev=>sel?prev.filter(x=>x!==s.key):[...prev,s.key]);}} style={{padding:"6px 12px",borderRadius:999,border:`1px solid ${sel?th.accent:th.border}`,background:sel?th.accent+"22":"transparent",color:sel?th.accent:th.sub,fontSize:11,fontWeight:700,cursor:"pointer"}}>{s.icon} {getSvcName(s)}</button>);})}</div><div style={{marginBottom:12}}><div style={{fontSize:12,color:th.sub,fontWeight:700,marginBottom:6}}>{t.calcComplex}: ×{calcComplexity}</div><input type="range" min={1} max={3} step={0.5} value={calcComplexity} onChange={e=>setCalcComplexity(+e.target.value)} style={{width:"100%",accentColor:th.accent}}/></div><div style={{marginBottom:14}}><div style={{fontSize:12,color:th.sub,fontWeight:700,marginBottom:6}}>{t.calcUrgent}: ×{calcUrgent}</div><input type="range" min={1} max={2} step={0.25} value={calcUrgent} onChange={e=>setCalcUrgent(+e.target.value)} style={{width:"100%",accentColor:th.accent}}/></div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"14px 16px",borderRadius:14,background:th.surface,border:`1px solid ${th.accent}40`}}><span style={{fontSize:14,fontWeight:700,color:th.text}}>{t.calcTotal}:</span><span style={{fontSize:22,fontWeight:900,color:th.accent}}>{fmt(calcTotal2)}</span></div><button onClick={()=>{SFX.order();openTg("Rivaldsg",`Калькулятор: ${calcItems.join(",")} ×${calcComplexity} ×${calcUrgent} = ~${fmt(calcTotal2)}`);}} style={{width:"100%",marginTop:12,background:th.grad,color:th.btnTxt,border:"none",borderRadius:14,padding:"13px",fontSize:14,fontWeight:800,cursor:"pointer",boxShadow:th.shadow}}>✈ {t.orderBtn}</button></div>{cart.length>0&&(<div style={{background:th.surface,borderRadius:20,border:`1px solid ${th.border}`,padding:"18px",animation:"cardIn .3s ease both"}}><div style={{fontSize:14,fontWeight:800,color:th.text,marginBottom:14}}>{t.cartTitle}</div>{cart.map(item=>(<div key={item.id} style={{display:"flex",justifyContent:"space-between",marginBottom:8,fontSize:13}}><span style={{color:th.sub}}>{item.name} ×{item.qty}</span><span style={{color:th.text,fontWeight:700}}>{fmt(item.priceUSD*item.qty)}</span></div>))}<div style={{borderTop:`1px solid ${th.border}`,marginTop:10,paddingTop:10}}>{cartTotal.disc>0&&(<div style={{display:"flex",justifyContent:"space-between",fontSize:12,color:"#10b981",fontWeight:700,marginBottom:6}}><span>{t.discount}</span><span>−{fmt(cartTotal.disc)}</span></div>)}<div style={{display:"flex",justifyContent:"space-between",fontSize:16,fontWeight:900}}><span style={{color:th.text}}>{t.finalPrice}</span><span style={{color:th.accent}}>{fmt(cartTotal.total)}</span></div></div><div style={{display:"flex",gap:8,marginTop:14}}><button onClick={()=>{clearCart();SFX.clear();}} style={{padding:"10px 16px",borderRadius:12,border:`1px solid ${th.border}`,background:"transparent",color:th.sub,cursor:"pointer",fontSize:12,fontWeight:700}}>{t.clearCart}</button><button onClick={()=>{SFX.order();const list=cart.map(i=>`${i.name} ×${i.qty}`).join(", ");openTg("Rivaldsg",`Заказ: ${list}. Сумма: ${fmt(cartTotal.total)}`);}} style={{flex:1,background:th.grad,color:th.btnTxt,border:"none",borderRadius:12,padding:"11px",fontSize:13,fontWeight:800,cursor:"pointer",boxShadow:th.shadow}}>{t.orderAll} — {fmt(cartTotal.total)}</button></div></div>)}</div>); }
