function MoreTab({th,t,lang,showToast}) { const [section,setSection]=useState("about"); const [expandedFaq,setExpandedFaq]=useState(null); const [aiIdea,setAiIdea]=useState(""); const [aiLoading,setAiLoading]=useState(false); const [aiHistory,setAiHistory]=useState(()=>ls.get("rs_ai_hist",[])); const [likes,setLikes]=useState(()=>ls.get("rs_likes",{})); const [reviewSearch,setReviewSearch]=useState(""); const [ratingFilter,setRatingFilter]=useState(0); const [expanded,setExpanded]=useState(null); const faq=FAQ_DATA[lang]||FAQ_DATA.ru; const filteredReviews=useMemo(()=>REVIEWS.filter(r=>(ratingFilter===0||r.rating===ratingFilter)&&(reviewSearch===""||r.name.toLowerCase().includes(reviewSearch.toLowerCase())||r.text.toLowerCase().includes(reviewSearch.toLowerCase()))),[reviewSearch,ratingFilter]); const likeReview=id=>{SFX.like();setLikes(prev=>{const n={...prev,[id]:(prev[id]||0)+1};ls.set("rs_likes",n);return n;});}; const genIdea=()=>{SFX.ai();setAiLoading(true);setTimeout(()=>{const pool=AI_IDEAS.filter(i=>!aiHistory.slice(-5).includes(i));const list=pool.length>0?pool:AI_IDEAS;const idea=list[Math.floor(Math.random()*list.length)];setAiIdea(idea);const nh=[...aiHistory.slice(-9),idea];setAiHistory(nh);ls.set("rs_ai_hist",nh);setAiLoading(false);SFX.aiDone();showToast("✧ Idea!","success");},1100+Math.random()*700);}; const avgRating=(REVIEWS.reduce((s,r)=>s+r.rating,0)/REVIEWS.length).toFixed(1); return (<div style={{display:"flex",flexDirection:"column",gap:12}}><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:6}}>{[["about",t.aboutTitle,"◎"],["reviews",t.reviewsTitle,"✦"],["faq",t.faqTitle,"?"],["ai",t.aiTitle,"✧"]].map(([id,label,icon])=>(<button key={id} onClick={()=>{setSection(id);SFX.tab();}} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:4,padding:"10px 4px",borderRadius:14,border:`1px solid ${section===id?th.accent:th.border}`,background:section===id?th.accent+"22":th.card,cursor:"pointer"}}><span style={{fontSize:18,color:section===id?th.accent:th.sub}}>{icon}</span><span style={{fontSize:10,fontWeight:700,color:section===id?th.accent:th.sub}}>{label}</span></button>))}</div>{section==="about"&&(<div style={{display:"flex",flexDirection:"column",gap:10,animation:"cardIn .35s ease both"}}><div style={{background:th.card,borderRadius:22,border:`1px solid ${th.border}`,overflow:"hidden"}}><div style={{height:90,background:th.grad,position:"relative"}}><div style={{position:"absolute",bottom:-28,left:20,width:56,height:56,borderRadius:18,background:th.surface,border:`3px solid ${th.card}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,boxShadow:th.shadow}}>✦</div></div><div style={{padding:"36px 20px 20px"}}><div style={{fontSize:20,fontWeight:900,color:th.text}}>Rival</div><div style={{fontSize:12,color:th.accent,fontWeight:700,marginBottom:10}}>@Rivaldsg · Graphic Designer</div><p style={{fontSize:13,color:th.sub,lineHeight:1.7,whiteSpace:"pre-line",margin:0}}>{t.aboutText}</p></div></div><div style={{background:th.card,borderRadius:20,border:`1px solid ${th.border}`,padding:"16px"}}>{[{icon:"✈",label:"Telegram",sub:"@Rivaldsg",url:"https://t.me/Rivaldsg",color:"#229ED9"},{icon:"▶",label:"VK",sub:"vk.com/rivaldsg",url:"https://vk.com/rivaldsg",color:"#4C75A3"},{icon:"◈",label:"Behance",sub:"Portfolio",url:"https://behance.net/rivaldsg",color:"#1769FF"}].map(s=>(<button key={s.label} onClick={()=>{window.open(s.url,"_blank");SFX.tap();}} style={{display:"flex",alignItems:"center",gap:12,padding:"12px 14px",borderRadius:14,border:`1px solid ${th.border}`,background:"transparent",cursor:"pointer",width:"100%",marginBottom:6}}><div style={{width:38,height:38,borderRadius:12,background:s.color+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,color:s.color,flexShrink:0}}>{s.icon}</div><div style={{flex:1,textAlign:"left"}}><div style={{fontSize:13,fontWeight:700,color:th.text}}>{s.label}</div><div style={{fontSize:11,color:th.sub}}>{s.sub}</div></div><span style={{color:th.sub,fontSize:16}}>›</span></button>))}</div><button onClick={()=>{SFX.order();openTg("Rivaldsg","Привет!");}} style={{background:th.grad,color:th.btnTxt,border:"none",borderRadius:18,padding:"16px",fontSize:15,fontWeight:800,cursor:"pointer",boxShadow:th.shadow}}>✈ {t.toTelegram}</button></div>)}{section==="reviews"&&(<div style={{display:"flex",flexDirection:"column",gap:10,animation:"cardIn .35s ease both"}}><div style={{display:"flex",gap:10,alignItems:"flex-start"}}><div style={{flex:1}}><div style={{fontSize:18,fontWeight:900,color:th.text}}>{t.reviewsTitle}</div><div style={{fontSize:12,color:th.sub}}>{REVIEWS.length} reviews</div></div><div style={{background:th.card,borderRadius:14,border:`1px solid ${th.border}`,padding:"10px 14px",textAlign:"center"}}><div style={{fontSize:24,fontWeight:900,color:th.accent}}>{avgRating}</div><div style={{fontSize:12,color:"#fbbf24"}}>★★★★★</div></div></div><div style={{position:"relative"}}><span style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",fontSize:14,color:th.sub}}>◎</span><input value={reviewSearch} onChange={e=>setReviewSearch(e.target.value)} placeholder={t.reviewSearch} style={{width:"100%",padding:"10px 12px 10px 36px",borderRadius:14,border:`1px solid ${th.border}`,background:th.card,color:th.text,fontSize:13,outline:"none",fontFamily:"inherit",boxSizing:"border-box"}}/></div><div style={{display:"flex",gap:6,overflowX:"auto",scrollbarWidth:"none"}}>{[0,5,4,3].map(r=>(<button key={r} onClick={()=>{setRatingFilter(r);SFX.filter();}} style={{whiteSpace:"nowrap",padding:"6px 12px",borderRadius:999,fontSize:11,fontWeight:700,cursor:"pointer",flexShrink:0,background:ratingFilter===r?th.accent+"22":"transparent",color:ratingFilter===r?th.accent:th.sub,border:`1px solid ${ratingFilter===r?th.accent:th.border}`}}>{r===0?t.allRatings:"★".repeat(r)}</button>))}</div>{filteredReviews.map((r,i)=>{const likeCount=likes[r.id]||0;const exp=expanded===r.id;return(<div key={r.id} style={{background:th.card,borderRadius:18,border:`1px solid ${th.border}`,padding:"14px 16px",animation:`cardIn .35s ease ${i*.04}s both`}}><div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}><div style={{width:40,height:40,borderRadius:14,background:th.grad,display:"flex",alignItems:"center",justifyContent:"center",fontSize:17,fontWeight:900,color:th.btnTxt,flexShrink:0,boxShadow:th.shadow}}>{r.name[0]}</div><div style={{flex:1}}><div style={{fontSize:13,fontWeight:800,color:th.text}}>{r.name}</div><div style={{fontSize:10,color:th.accent}}>@{r.tg}</div></div><div style={{fontSize:12,color:"#fbbf24"}}>{"★".repeat(r.rating)}</div></div><p style={{fontSize:13,color:th.sub,lineHeight:1.6,margin:"0 0 12px",cursor:"pointer",display:"-webkit-box",WebkitLineClamp:exp?100:2,WebkitBoxOrient:"vertical",overflow:"hidden"}} onClick={()=>setExpanded(exp?null:r.id)}>"{r.text}"</p><div style={{display:"flex",gap:8}}><button onClick={()=>{window.open(`https://t.me/${r.tg}`,"_blank");SFX.tap();}} style={{fontSize:11,color:th.accent,background:th.accent+"15",border:`1px solid ${th.accent}40`,borderRadius:8,padding:"5px 10px",cursor:"pointer",fontWeight:700}}>✈ TG</button><button onClick={()=>likeReview(r.id)} style={{display:"flex",alignItems:"center",gap:4,fontSize:11,color:likeCount>0?th.accent:th.sub,background:likeCount>0?th.accent+"15":"transparent",border:`1px solid ${likeCount>0?th.accent+"40":th.border}`,borderRadius:8,padding:"5px 10px",cursor:"pointer",fontWeight:700}}>♡ {likeCount>0?likeCount:""}</button></div></div>);})}</div>)}{section==="faq"&&(<div style={{display:"flex",flexDirection:"column",gap:8,animation:"cardIn .35s ease both"}}><div style={{fontSize:18,fontWeight:900,color:th.text}}>{t.faqTitle}</div>{faq.map((item,i)=>{const exp=expandedFaq===i;return(<div key={i} style={{background:th.card,borderRadius:18,border:`1px solid ${exp?th.accent:th.border}`,overflow:"hidden",boxShadow:exp?th.shadow:"none",animation:`cardIn .3s ease ${i*.06}s both`}}><button onClick={()=>{setExpandedFaq(exp?null:i);SFX.faq();}} style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 16px",background:"none",border:"none",color:th.text,cursor:"pointer",fontSize:13,fontWeight:700,textAlign:"left",fontFamily:"inherit"}}><span style={{flex:1}}>{item.q}</span><span style={{color:th.accent,fontSize:20,fontWeight:300,flexShrink:0,transition:"transform .25s",transform:exp?"rotate(45deg)":"none"}}>+</span></button>{exp&&<div style={{padding:"0 16px 16px",fontSize:13,color:th.sub,lineHeight:1.7,whiteSpace:"pre-line",animation:"fadeDown .25s ease"}}>{item.a}</div>}</div>);})}</div>)}{section==="ai"&&(<div style={{display:"flex",flexDirection:"column",gap:12,animation:"cardIn .35s ease both"}}><div><div style={{fontSize:18,fontWeight:900,color:th.text}}>{t.aiTitle}</div><div style={{fontSize:12,color:th.sub,marginTop:2}}>{t.aiSub}</div></div><div style={{minHeight:120,background:th.card,borderRadius:20,border:`1px solid ${aiIdea?th.accent:th.border}`,padding:"20px",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",boxShadow:aiIdea?th.shadow:"none",gap:12}}>{aiLoading?(<div style={{textAlign:"center",color:th.sub}}><div style={{fontSize:36,animation:"spin 1s linear infinite",display:"inline-block",marginBottom:10}}>✧</div><div style={{fontSize:13,fontWeight:600}}>{t.aiLoading}</div></div>):aiIdea?(<><p style={{fontSize:14,color:th.text,lineHeight:1.7,margin:0,textAlign:"center"}}>{aiIdea}</p><button onClick={()=>{SFX.copy();try{navigator.clipboard.writeText(aiIdea);}catch{};showToast(t.copied,"success");}} style={{padding:"7px 14px",borderRadius:10,border:`1px solid ${th.border}`,background:"transparent",color:th.sub,cursor:"pointer",fontSize:12,fontWeight:700}}>⎘ Copy</button></>):(<div style={{textAlign:"center",color:th.sub}}><div style={{fontSize:40,marginBottom:10}}>✧</div><div style={{fontSize:13}}>{t.aiEmpty}</div></div>)}</div><button onClick={genIdea} disabled={aiLoading} style={{background:aiLoading?"transparent":th.grad,color:aiLoading?th.sub:th.btnTxt,border:aiLoading?`1px solid ${th.border}`:"none",borderRadius:16,padding:"15px",fontSize:15,fontWeight:800,cursor:aiLoading?"not-allowed":"pointer",boxShadow:aiLoading?"none":th.shadow}}>{aiLoading?"...":t.aiBtn}</button>{aiHistory.length>0&&(<div style={{background:th.card,borderRadius:18,border:`1px solid ${th.border}`,padding:"14px"}}><div style={{fontSize:12,fontWeight:800,color:th.sub,marginBottom:10,letterSpacing:".05em",textTransform:"uppercase"}}>{t.aiHist}</div>{[...aiHistory].reverse().slice(0,5).map((idea,i)=>(<div key={i} onClick={()=>{setAiIdea(idea);SFX.tap();}} style={{fontSize:12,color:th.sub,padding:"9px 12px",borderRadius:10,border:`1px solid ${th.border}`,cursor:"pointer",marginBottom:4,display:"flex",alignItems:"center",gap:8}}><span style={{flexShrink:0,color:th.accent}}>✧</span><span style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{idea}</span></div>))}</div>)}</div>)}</div>); }
// ── IMAGE MODAL ──
function ImageModal({item,th,t,onClose,wishlist,toggleWishlist,showToast}) { useEffect(()=>{document.body.style.overflow="hidden";return()=>{document.body.style.overflow="";};},[]);const wl=wishlist.includes(item.id); return (<div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.92)",zIndex:9000,display:"flex",alignItems:"flex-end",animation:"fadeIn .25s ease",backdropFilter:"blur(8px)"}}><div onClick={e=>e.stopPropagation()} style={{width:"100%",maxWidth:480,margin:"0 auto",background:th.nav,borderRadius:"24px 24px 0 0",border:`1px solid ${th.border}`,animation:"sheetUp .35s cubic-bezier(.4,0,.2,1) both",overflow:"hidden"}}><div style={{display:"flex",justifyContent:"center",padding:"12px 0 0"}}><div style={{width:36,height:4,borderRadius:999,background:th.border}}/></div><div style={{position:"relative",margin:"12px 16px 0"}}><img src={item.img} alt={item.title} style={{width:"100%",borderRadius:18,display:"block",maxHeight:"50vh",objectFit:"cover"}}/><button onClick={onClose} style={{position:"absolute",top:10,right:10,width:32,height:32,borderRadius:10,background:"rgba(0,0,0,.7)",border:"none",color:"#fff",cursor:"pointer",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button>{item.popular&&<div style={{position:"absolute",top:10,left:10,padding:"4px 10px",borderRadius:999,background:th.accent,color:th.btnTxt,fontSize:11,fontWeight:800}}>★ TOP</div>}</div><div style={{padding:"16px 20px 24px"}}><div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:8}}><div><div style={{fontSize:20,fontWeight:900,color:th.text}}>{item.title}</div><div style={{fontSize:12,color:th.sub,marginTop:2}}>{item.cat} · {item.desc}</div></div><button onClick={()=>{toggleWishlist(item.id);SFX.wishlist();}} style={{width:38,height:38,borderRadius:12,border:`1px solid ${wl?th.accent:th.border}`,background:wl?th.accent+"22":"transparent",color:wl?th.accent:th.sub,cursor:"pointer",fontSize:18,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>{wl?"♥":"♡"}</button></div><div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:16}}>{item.tags.map(tag=>(<span key={tag} style={{padding:"3px 10px",borderRadius:999,background:th.accent+"18",color:th.accent,fontSize:11,fontWeight:700}}>#{tag}</span>))}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}><button onClick={()=>{SFX.order();openTg("Rivaldsg",`Хочу: ${item.title}`);}} style={{background:th.grad,color:th.btnTxt,border:"none",borderRadius:14,padding:"13px",fontSize:14,fontWeight:800,cursor:"pointer",boxShadow:th.shadow}}>✈ {t.orderBtn}</button><button onClick={()=>{SFX.copy();try{navigator.clipboard.writeText(item.img);}catch{};showToast(t.copied,"success");}} style={{background:th.card,color:th.text,border:`1px solid ${th.border}`,borderRadius:14,padding:"13px",fontSize:13,fontWeight:700,cursor:"pointer"}}>⎘ Copy</button></div></div></div></div>); }
// ── SPLASH ──
function SplashScreen({th,onDone}) { const [progress,setProgress]=useState(0); useEffect(()=>{SFX.boot();let p=0;const iv=setInterval(()=>{p+=Math.random()*15+5;setProgress(Math.min(p,100));if(p>=100){clearInterval(iv);setTimeout(onDone,300);}},80);return()=>clearInterval(iv);},[]);return (<div style={{position:"fixed",inset:0,background:th.bg,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",zIndex:10000,gap:24,animation:"fadeIn .3s ease"}}><div style={{fontSize:60,animation:"splashBounce 1s ease infinite"}}>✦</div><div style={{textAlign:"center"}}><div style={{fontSize:28,fontWeight:900,color:th.text}}>Rival Studio</div><div style={{fontSize:13,color:th.sub,marginTop:4}}>{isTg?"Telegram Mini App":"Graphic Design"}</div></div><div style={{width:200,height:3,borderRadius:999,background:th.border,overflow:"hidden"}}><div style={{height:"100%",borderRadius:999,background:th.grad,width:`${progress}%`,transition:"width .08s ease"}}/></div><div style={{fontSize:11,color:th.sub}}>{Math.round(progress)}%</div></div>); }
// ═══════════════════════════════════════════════════════════
// ◆◆◆ MAIN APP ◆◆◆
// ═══════════════════════════════════════════════════════════
export default function App() {
  const [theme,setTheme]=useState(()=>{const id=ls.get("rs_theme","void");return THEMES[id]||THEMES.void;});
  const [lang,setLang]=useState(()=>{const l=ls.get("rs_lang","ru");return LANGS[l]?l:"ru";});
  const [soundOn,setSoundOn]=useState(()=>{const s=ls.get("rs_sound",true);_soundEnabled=s;return s;});
  const [volume,setVolume]=useState(()=>{const v=ls.get("rs_volume",.6);_volume=v;return v;});
  const [tab,setTab]=useState("home");
  const [drawerOpen,setDrawerOpen]=useState(false);
  const [cart,setCart]=useState(()=>ls.get("rs_cart",[]));
  const [wishlist,setWishlist]=useState(()=>ls.get("rs_wl",[]));
  const [splash,setSplash]=useState(true);
  const [confetti,setConfetti]=useState(false);
  const [toasts,setToasts]=useState([]);
  const [selImage,setSelImage]=useState(null);
  const [streak,setStreak]=useState(()=>getStreak());
  const th=theme; const t=T[lang]||T.ru;
  useEffect(()=>{tgReady();},[]);
  useEffect(()=>{if(tab!=="home"||selImage||drawerOpen){const cb=()=>{if(selImage){setSelImage(null);SFX.close();}else if(drawerOpen){setDrawerOpen(false);}else{setTab("home");SFX.tab();}};tgBackBtn(true,cb);return()=>tgBackBtn(false,cb);}else{tgBackBtn(false);}},[tab,selImage,drawerOpen]);
  useEffect(()=>{const s=getStreak();setStreak(s);if(s.count>1){setTimeout(()=>{SFX.streak();showToast(`🔥 ${s.count} ${t.streakTitle}!`,"success");},1500);}},[]);
  useEffect(()=>{ls.set("rs_cart",cart);},[cart]);
  useEffect(()=>{ls.set("rs_wl",wishlist);},[wishlist]);
  const showToast=useCallback((msg,type="info")=>{const id=Date.now();setToasts(prev=>[...prev,{id,msg,type}]);setTimeout(()=>setToasts(prev=>prev.filter(t=>t.id!==id)),2800);},[]);
  const addToCart=useCallback((svc,name)=>{setCart(prev=>{const ex=prev.find(i=>i.id===svc.id);if(ex)return prev.map(i=>i.id===svc.id?{...i,qty:i.qty+1}:i);return[...prev,{...svc,name,qty:1}];});},[]);
  const removeFromCart=useCallback(id=>{setCart(prev=>prev.filter(i=>i.id!==id));},[]);
  const updateQty=useCallback((id,qty)=>{if(qty<1){removeFromCart(id);return;}setCart(prev=>prev.map(i=>i.id===id?{...i,qty}:i));},[removeFromCart]);
  const clearCart=useCallback(()=>setCart([]),[]);
  const cartCount=useMemo(()=>cart.reduce((s,i)=>s+i.qty,0),[cart]);
  const toggleWishlist=useCallback(id=>{setWishlist(prev=>{const n=prev.includes(id)?prev.filter(i=>i!==id):[...prev,id];ls.set("rs_wl",n);return n;});},[]);
  const addXPfn=useCallback(amount=>{const newData=addXP(amount);setStreak(newData);const oldLevel=getLevel(newData.xp-amount);const newLevel=getLevel(newData.xp);if(newLevel>oldLevel){setTimeout(()=>{SFX.levelUp();showToast(`🏆 Level ${newLevel}!`,"success");setConfetti(true);setTimeout(()=>setConfetti(false),3500);},300);}},[showToast]);
  const greeting=getGreeting(lang);
  return (
    <div style={{minHeight:"100dvh",background:th.bg,fontFamily:'"Nunito","Sora","DM Sans","Inter",system-ui,sans-serif',display:"flex",justifyContent:"center",position:"relative",overscrollBehavior:"none"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&display=swap');
        *,*::before,*::after{box-sizing:border-box;-webkit-tap-highlight-color:transparent;}
        ::-webkit-scrollbar{width:0;height:0;}*{scrollbar-width:none;}
        html{scroll-behavior:smooth;overscroll-behavior:none;overflow:hidden;height:100%;}
        body{margin:0;padding:0;overflow-x:hidden;overflow-y:auto;height:100%;overscroll-behavior-y:none;-webkit-overflow-scrolling:touch;}
        button{font-family:inherit;}input{font-family:inherit;}img{-webkit-user-drag:none;user-select:none;}
        @keyframes fadeIn{from{opacity:0}to{opacity:1}}
        @keyframes fadeDown{from{opacity:0;transform:translateY(-10px)}to{opacity:1;transform:none}}
        @keyframes cardIn{from{opacity:0;transform:translateY(22px) scale(.95)}to{opacity:1;transform:none}}
        @keyframes sheetUp{from{transform:translateY(100%)}to{transform:none}}
        @keyframes drawerSlide{from{transform:translateX(-100%)}to{transform:none}}
        @keyframes toastIn{from{opacity:0;transform:translateY(-14px) scale(.9)}to{opacity:1;transform:none}}
        @keyframes spin{to{transform:rotate(360deg)}}
        @keyframes blink{0%,100%{opacity:1}50%{opacity:0}}
        @keyframes ping{0%,100%{transform:scale(1);opacity:1}50%{transform:scale(1.4);opacity:.6}}
        @keyframes splashBounce{0%,100%{transform:scale(1) rotate(0deg)}50%{transform:scale(1.2) rotate(15deg)}}
        input[type=range]{-webkit-appearance:none;height:4px;border-radius:99px;outline:none;}
        input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;width:18px;height:18px;border-radius:50%;background:${th.accent};cursor:pointer;box-shadow:0 2px 8px ${th.glow};}
        .swiper{overflow:visible!important;}
        @media(prefers-reduced-motion:reduce){*{animation-duration:.01ms!important;transition-duration:.01ms!important;}}
      `}</style>
      {splash&&<SplashScreen th={th} onDone={()=>setSplash(false)}/>}
      <ParticlesBg accent={th.accent}/>
      <ToastSystem toasts={toasts}/>
      {confetti&&<Confetti active={confetti} accent={th.accent}/>}
      <SideDrawer open={drawerOpen} onClose={()=>setDrawerOpen(false)} th={th} t={t} theme={theme} setTheme={setTheme} lang={lang} setLang={setLang} soundOn={soundOn} setSoundOn={setSoundOn} volume={volume} setVolume={setVolume}/>
      <div style={{width:"100%",maxWidth:480,display:"flex",flexDirection:"column",minHeight:"100dvh",position:"relative",zIndex:1}}>
        <header style={{position:"sticky",top:0,zIndex:100,display:"flex",alignItems:"center",justifyContent:"space-between",padding:"12px 16px",background:th.nav,borderBottom:`1px solid ${th.border}`}}>
          <button onClick={()=>{SFX.drawer();setDrawerOpen(true);}} style={{display:"flex",flexDirection:"column",gap:4.5,width:32,height:32,justifyContent:"center",alignItems:"center",background:"none",border:"none",cursor:"pointer",padding:0}}>{[0,1,2].map(i=>(<div key={i} style={{width:i===1?16:22,height:2,borderRadius:999,background:th.sub}}/>))}</button>
          <div style={{display:"flex",alignItems:"center",gap:8,position:"absolute",left:"50%",transform:"translateX(-50%)"}}><div style={{width:28,height:28,borderRadius:9,background:th.grad,display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,color:th.btnTxt,boxShadow:th.shadow}}>✦</div><span style={{fontSize:15,fontWeight:900,color:th.text}}>{t.appName}</span></div>
          <div style={{display:"flex",alignItems:"center",gap:8}}><div style={{display:"flex",alignItems:"center",gap:4,padding:"4px 10px",borderRadius:999,background:th.accent+"18",border:`1px solid ${th.accent}30`}}><span style={{fontSize:12}}>🔥</span><span style={{fontSize:11,fontWeight:800,color:th.accent}}>{streak.count}</span></div><button onClick={()=>{SFX.tap();openTg("Rivaldsg");}} style={{width:32,height:32,borderRadius:10,border:`1px solid ${th.border}`,background:"none",color:th.accent,cursor:"pointer",fontSize:18,display:"flex",alignItems:"center",justifyContent:"center"}}>✈</button></div>
        </header>
        {tab==="home"&&<div style={{padding:"10px 16px 0",fontSize:12,color:th.sub,fontWeight:600}}>{greeting} 👋</div>}
        <main style={{flex:1,padding:"14px 16px 100px",overflowY:"auto",WebkitOverflowScrolling:"touch",overscrollBehavior:"contain"}}>
          <div key={tab} style={{animation:"cardIn .35s ease both"}}>
            {tab==="home"&&<HomeTab th={th} t={t} lang={lang} onGoGallery={()=>setTab("gallery")} onGoCourses={()=>setTab("courses")} onGoPricing={()=>setTab("pricing")} onGoMore={()=>setTab("more")} cartCount={cartCount} streak={streak}/>}
            {tab==="gallery"&&<GalleryTab th={th} t={t} lang={lang} wishlist={wishlist} toggleWishlist={toggleWishlist} onOpenImage={item=>setSelImage(item)}/>}
            {tab==="courses"&&<CoursesTab th={th} t={t} lang={lang} showToast={showToast} addXPfn={addXPfn}/>}
            {tab==="pricing"&&<PricingTab th={th} t={t} lang={lang} cart={cart} addToCart={addToCart} removeFromCart={removeFromCart} updateQty={updateQty} clearCart={clearCart} showToast={showToast}/>}
            {tab==="more"&&<MoreTab th={th} t={t} lang={lang} showToast={showToast}/>}
          </div>
        </main>
        <BottomNav active={tab} onChange={setTab} th={th} t={t} cartCount={cartCount}/>
      </div>
      {selImage&&<ImageModal item={selImage} th={th} t={t} onClose={()=>{setSelImage(null);SFX.close();}} wishlist={wishlist} toggleWishlist={toggleWishlist} showToast={showToast}/>}
    </div>
  );
}
